from string_utils.manipulation import __StringFormatter

def test__ensure_left_space_only():
    """
    Test whether the __ensure_left_space_only method raises an error when invoked.
    """
    formatter = __StringFormatter("test")
    try:
        # Simulating a regex_match group being passed as it would be in normal use
        class MockMatch:
            def group(self, index):
                return "content"

        mock_match = MockMatch()
        output = formatter.__ensure_left_space_only(mock_match)  # Should raise an error in the mutant
        return output  # If it does not raise as expected, we will get the output
    except Exception as e:
        print(f"Exception caught: {str(e)}")  # Catch and print the exception
